agents.schema:
{
  "type": "object",
  "properties": {
    "user_message": {
      "type": "string",
      "required": true,
      "description": "The raw message from the user to detect intent and route accordingly"
    }
  }
}

{
  "type": "object",
  "properties": {
    "raw_response": {
      "type": "string",
      "required": true,
      "description": "The raw output from the intent-specific LLM node that needs to be formatted into a final clean response"
    }
  }
}

values.schema:
{
  "type": "object",
  "properties": {
    "intent": {
      "type": "string",
      "required": true,
      "enum": ["RECIPE", "MENU", "GROCERY", "GENERAL"],
      "description": "The detected intent from the user message"
    }
  }
}

{
  "type": "object",
  "properties": {
    "type": { "type": "string", "required": true, "description": "Always the string: recipe" },
    "title": { "type": "string", "required": true, "description": "Name of the recipe" },
    "servings": { "type": "number", "required": true, "description": "Number of servings" },
    "prepTime": { "type": "string", "required": true, "description": "Preparation time e.g. 15 mins" },
    "cookTime": { "type": "string", "required": true, "description": "Cooking time e.g. 30 mins" },
    "ingredients": { "type": "array", "required": true, "description": "List of ingredient objects with amount, unit, name" },
    "steps": { "type": "array", "required": true, "description": "Ordered list of step strings" },
    "tags": { "type": "array", "required": true, "description": "Short keyword tags for the recipe" }
  }
}

{
  "type": "object",
  "properties": {
    "type": { "type": "string", "required": true, "description": "Always the string: menu" },
    "days": { "type": "array", "required": true, "description": "Array of day objects each with: day (string), breakfast (string), lunch (string), dinner (string)" }
  }
}

{
  "type": "object",
  "properties": {
    "type": { "type": "string", "required": true, "description": "Always the string: grocery" },
    "items": { "type": "array", "required": true, "description": "Array of grocery item objects each with: amount (string), unit (string), name (string), category (string). Valid categories: Vegetables, Fruits, Grains, Dairy, Protein, Spices, Condiments, Beverages, Other" }
  }
}

{
  "type": "object",
  "properties": {
    "type": { "type": "string", "required": true, "description": "Always the string: general" },
    "message": { "type": "string", "required": true, "description": "Clear, friendly, practical cooking answer under 200 words" }
  }
}

{
  "type": "object",
  "properties": {
    "formatted_response": {
      "type": "string",
      "required": true,
      "description": "The final human-readable response to show to the user based on the structured JSON input"
    },
    "response_type": {
      "type": "string",
      "required": true,
      "description": "One of: recipe, menu, grocery, general"
    }
  }
}
